INSERT INTO glossar_terms (term, definition, category, lawReference, lawLink) VALUES
('Abgeschlossenheitsbescheinigung', 'Bescheinigung der Baubehörde, dass eine Eigentumswohnung oder Teileigentumseinheit baulich von anderen Wohnungen und Räumen hinreichend abgeschlossen ist. Voraussetzung für die Aufteilung in Wohnungseigentum.', 'Recht', '§ 7 Abs. 4 Nr. 2 WEG', 'https://www.gesetze-im-internet.de/woeigg/__7.html'),
('Abnahme', 'Förmliche Erklärung des Bestellers, dass er das Werk (z.B. Neubau, Sanierung) als im Wesentlichen vertragsgemäß anerkennt. Wichtiger Zeitpunkt für Gewährleistungsfristen und Gefahrübergang.', 'Bau', '§ 640 BGB', 'https://www.gesetze-im-internet.de/bgb/__640.html'),
('Allgemeine Geschäftsbedingungen (AGB)', 'Vorformulierte Vertragsbedingungen, die eine Vertragspartei der anderen bei Vertragsschluss stellt. Unterliegen besonderer Inhaltskontrolle zum Schutz des Vertragspartners.', 'Recht', '§ 305 BGB', 'https://www.gesetze-im-internet.de/bgb/__305.html'),
('Altlast', 'Kontaminierung des Bodens oder Grundwassers durch frühere Nutzung (z.B. Industriestandort). Kann zu Sanierungspflichten und Wertminderungen führen.', 'Bau', '§ 2 BBodSchG', 'https://www.gesetze-im-internet.de/bbodschg/__2.html'),
('Ankaufsrecht', 'Vertragliches Recht, eine Immobilie zu einem festgelegten Preis oder nach festgelegten Kriterien zu erwerben. Kann als Vormerkung im Grundbuch eingetragen werden.', 'Recht', '§ 463 BGB', 'https://www.gesetze-im-internet.de/bgb/__463.html'),
('Annuität', 'Gleichbleibende Zahlungsrate bei Annuitätendarlehen, bestehend aus Zins- und Tilgungsanteil. Im Zeitverlauf sinkt der Zinsanteil, während der Tilgungsanteil steigt.', 'Finanzierung', '§ 488 BGB', 'https://www.gesetze-im-internet.de/bgb/__488.html'),
('Auflassung', 'Die dingliche Einigung zwischen Verkäufer und Käufer über den Eigentumsübergang an einem Grundstück. Sie muss bei gleichzeitiger Anwesenheit beider Teile vor einer zuständigen Stelle (Notar) erklärt werden.', 'Recht', '§ 925 BGB', 'https://www.gesetze-im-internet.de/bgb/__925.html'),
('Auflassungsvormerkung', 'Sicherungsmittel für den Käufer im Grundbuch. Sie verhindert, dass der Verkäufer das Grundstück anderweitig verkauft oder belastet, bevor der eigentliche Eigentumsübergang vollzogen ist.', 'Recht', '§ 883 BGB', 'https://www.gesetze-im-internet.de/bgb/__883.html'),
('Bauabzugssteuer', 'Steuerabzug von 15% bei Bauleistungen, wenn der Leistungsempfänger keine Freistellungsbescheinigung des Finanzamts vorlegt. Soll Schwarzarbeit verhindern.', 'Bau', '§ 48 EStG', 'https://www.gesetze-im-internet.de/estg/__48.html'),
('Baulast', 'Öffentlich-rechtliche Verpflichtung des Grundstückseigentümers gegenüber der Baubehörde, etwas zu tun, zu dulden oder zu unterlassen (z.B. Stellplätze nachweisen).', 'Bau', NULL, NULL),
('Bauträger', 'Unternehmer, der Grundstücke in eigenem Namen und für eigene Rechnung bebaut und diese dann (meist schlüsselfertig) an Erwerber verkauft. Er unterliegt der Makler- und Bauträgerverordnung (MaBV).', 'Bau', '§ 34c Abs. 1 Nr. 3a GewO', 'https://www.gesetze-im-internet.de/gewo/__34c.html'),
('Beleihungswert', 'Wert einer Immobilie, den eine Bank langfristig und nachhaltig als Sicherheit ansetzt. Liegt meist unter dem Verkehrswert (ca. 80-90%).', 'Finanzierung', '§ 16 PfandBG', 'https://www.gesetze-im-internet.de/pfandbg/__16.html'),
('Bestellerprinzip', 'Regelung bei der Vermietung von Wohnraum: Wer den Makler bestellt (beauftragt), muss ihn bezahlen. Gilt seit 2015 für Wohnraummietverträge.', 'Makler', '§ 2 Abs. 1a WoVermRG', 'https://www.gesetze-im-internet.de/wovermrg/__2.html'),
('Betriebskosten', 'Kosten, die dem Eigentümer durch das Eigentum oder den bestimmungsgemäßen Gebrauch des Gebäudes laufend entstehen (z.B. Heizung, Wasser, Müll). Können auf Mieter umgelegt werden.', 'Verwaltung', '§ 556 BGB, BetrKV', 'https://www.gesetze-im-internet.de/bgb/__556.html'),
('Bodenwert', 'Wert des unbebauten Grundstücks. Wird aus Bodenrichtwerten abgeleitet und ist Grundlage für das Sachwertverfahren.', 'Finanzierung', '§ 179 BauGB', 'https://www.gesetze-im-internet.de/bbaugb/__179.html'),
('Courtage', 'Die Vergütung (Provision) des Immobilienmaklers für die erfolgreiche Vermittlung oder den Nachweis einer Gelegenheit zum Abschluss eines Vertrags.', 'Makler', '§ 652 BGB', 'https://www.gesetze-im-internet.de/bgb/__652.html'),
('Damnum (Disagio)', 'Abschlag vom Nominalbetrag eines Darlehens, der als Zinsvorauszahlung dient. Reduziert die Auszahlungssumme, erhöht aber die steuerliche Absetzbarkeit.', 'Finanzierung', NULL, NULL),
('Denkmalschutz', 'Schutz von Bauwerken, die von geschichtlicher, künstlerischer oder städtebaulicher Bedeutung sind. Einschränkungen bei Umbau und Sanierung, aber auch Steuervorteile.', 'Bau', 'Länderspezifische Denkmalschutzgesetze', NULL),
('Dienstbarkeit', 'Ein dingliches Recht an einer fremden Sache, das dem Berechtigten eine bestimmte Nutzung gestattet (z.B. Wegerecht, Leitungsrecht) oder bestimmte Handlungen verbietet.', 'Recht', '§ 1018 BGB', 'https://www.gesetze-im-internet.de/bgb/__1018.html'),
('Duldungspflicht', 'Verpflichtung des Mieters, bestimmte Maßnahmen des Vermieters zu dulden (z.B. Modernisierung, Instandsetzung), auch wenn sie mit Beeinträchtigungen verbunden sind.', 'Recht', '§ 555d BGB', 'https://www.gesetze-im-internet.de/bgb/__555d.html'),
('Effektivzins', 'Tatsächlicher jährlicher Zinssatz eines Kredits unter Berücksichtigung aller Kosten (Nominalzins, Disagio, Gebühren). Ermöglicht Vergleich verschiedener Kreditangebote.', 'Finanzierung', '§ 6 PAngV', 'https://www.gesetze-im-internet.de/pangv/__6.html'),
('Eigentümerbescheinigung', 'Bescheinigung des Grundbuchamts über die Eigentumsverhältnisse eines Grundstücks. Wird oft bei Verkaufsverhandlungen verlangt.', 'Recht', NULL, NULL),
('Eigentümerversammlung', 'Das oberste Beschlussorgan einer Wohnungseigentümergemeinschaft (WEG). Hier werden Entscheidungen über die Verwaltung, Instandhaltung und Kostenverteilung getroffen.', 'Verwaltung', '§ 23 WEG', 'https://www.gesetze-im-internet.de/woeigg/__23.html'),
('Energieausweis', 'Pflichtdokument bei Verkauf und Vermietung, das über die energetische Qualität eines Gebäudes informiert. Unterscheidung zwischen Bedarfs- und Verbrauchsausweis.', 'Bau', '§ 80 GEG', 'https://www.gesetze-im-internet.de/geg/__80.html'),
('Erbbaurecht', 'Das veräußerliche und vererbliche Recht, auf oder unter der Oberfläche eines Grundstücks ein Bauwerk zu haben. Der Erbbauberechtigte zahlt dafür einen Erbbauzins an den Grundstückseigentümer.', 'Recht', '§ 1 ErbbauRG', 'https://www.gesetze-im-internet.de/erbbaurg/__1.html'),
('Ertragswertverfahren', 'Wertermittlungsverfahren für vermietete Immobilien. Der Wert ergibt sich aus dem kapitalisierten Reinertrag plus Bodenwert.', 'Finanzierung', '§§ 17-20 ImmoWertV', 'https://www.gesetze-im-internet.de/immowertv_2021/__17.html'),
('Exposé', 'Verkaufsunterlage, die eine Immobilie beschreibt. Es enthält wichtige Daten, Fakten, Bilder und Pläne und dient als Informationsgrundlage für Interessenten.', 'Makler', NULL, NULL),
('Fernabsatzvertrag', 'Vertrag, der ausschließlich über Fernkommunikationsmittel (E-Mail, Telefon, Internet) geschlossen wird. Hier besteht oft ein Widerrufsrecht für Verbraucher.', 'Recht', '§ 312c BGB', 'https://www.gesetze-im-internet.de/bgb/__312c.html'),
('Festzins', 'Zinssatz, der für einen vereinbarten Zeitraum (Zinsbindung) fest vereinbart ist und sich nicht ändert. Üblich sind 5, 10, 15 oder 20 Jahre.', 'Finanzierung', NULL, NULL),
('Flurkarte', 'Amtliche Karte, die die Lage, Form und Grenzen von Grundstücken (Flurstücken) sowie die Bebauung darstellt. Teil des Liegenschaftskatasters.', 'Bau', NULL, NULL),
('Flurstück', 'Kleinste Buchungseinheit des Liegenschaftskatasters. Jedes Grundstück besteht aus einem oder mehreren Flurstücken mit eindeutiger Nummer.', 'Bau', NULL, NULL),
('Formvorschriften', 'Gesetzliche Anforderungen an die Form von Rechtsgeschäften (z.B. notarielle Beurkundung bei Grundstückskaufverträgen). Nichteinhaltung führt zur Nichtigkeit.', 'Recht', '§ 311b BGB', 'https://www.gesetze-im-internet.de/bgb/__311b.html'),
('Gemeinschaftseigentum', 'Teile eines Gebäudes und Grundstücks, die nicht im Sondereigentum oder im Eigentum eines Dritten stehen (z.B. Dach, Treppenhaus, Außenwände).', 'Verwaltung', '§ 1 Abs. 5 WEG', 'https://www.gesetze-im-internet.de/woeigg/__1.html'),
('Gemeinschaftsordnung', 'Regelwerk einer Wohnungseigentümergemeinschaft, das die Rechte und Pflichten der Eigentümer sowie die Verwaltung und Nutzung regelt.', 'Verwaltung', '§ 10 WEG', 'https://www.gesetze-im-internet.de/woeigg/__10.html'),
('Gewährleistung', 'Haftung des Verkäufers oder Werkunternehmers für Mängel der Kaufsache oder des Werks. Beim Immobilienkauf meist 5 Jahre, bei Bauverträgen 5 Jahre ab Abnahme.', 'Recht', '§§ 434 ff., 633 ff. BGB', 'https://www.gesetze-im-internet.de/bgb/__434.html'),
('Grundbuch', 'Amtliches Register, das die Eigentumsverhältnisse und Belastungen von Grundstücken dokumentiert. Es genießt öffentlichen Glauben.', 'Recht', '§ 891 BGB', 'https://www.gesetze-im-internet.de/bgb/__891.html'),
('Grunderwerbsteuer', 'Steuer auf den Erwerb von Grundstücken. Bemessungsgrundlage ist der Kaufpreis, Steuersatz je nach Bundesland 3,5% bis 6,5%.', 'Finanzierung', '§ 1 GrEStG', 'https://www.gesetze-im-internet.de/grestg_1983/__1.html'),
('Grundflächenzahl (GRZ)', 'Gibt an, wie viel Quadratmeter Grundfläche je Quadratmeter Grundstücksfläche bebaut werden darf. Wird im Bebauungsplan festgesetzt.', 'Bau', '§ 19 BauNVO', 'https://www.gesetze-im-internet.de/baunvo/__19.html'),
('Grundschuld', 'Ein dingliches Recht, aus einem Grundstück die Zahlung einer bestimmten Geldsumme zu fordern. Häufigstes Sicherungsmittel für Immobilienkredite, da sie nicht an eine bestimmte Forderung gebunden ist (abstrakt).', 'Finanzierung', '§ 1191 BGB', 'https://www.gesetze-im-internet.de/bgb/__1191.html'),
('Grundstücksverkehrsgesetz (GrdstVG)', 'Regelt die Genehmigungspflicht bei land- und forstwirtschaftlichen Grundstücken zum Schutz vor Bodenspekulation.', 'Recht', 'GrdstVG', 'https://www.gesetze-im-internet.de/grdstvg/'),
('Haftung', 'Rechtliche Verantwortung für Schäden oder Mängel. Unterscheidung zwischen vertraglicher Haftung (Gewährleistung) und deliktischer Haftung (Schadensersatz).', 'Recht', '§§ 280 ff., 823 ff. BGB', 'https://www.gesetze-im-internet.de/bgb/__280.html'),
('Hausgeld', 'Monatliche Vorschusszahlung der Wohnungseigentümer an den Verwalter zur Deckung der laufenden Kosten (Bewirtschaftung, Instandhaltung, Verwaltung).', 'Verwaltung', '§ 28 WEG', 'https://www.gesetze-im-internet.de/woeigg/__28.html'),
('Hausverwaltung', 'Professionelle Verwaltung von Immobilien, entweder als WEG-Verwaltung (Wohnungseigentum) oder Mietverwaltung (Mietobjekte). Erfordert Erlaubnis nach § 34c GewO.', 'Verwaltung', '§ 34c Abs. 1 Nr. 3 GewO', 'https://www.gesetze-im-internet.de/gewo/__34c.html'),
('Hypothek', 'Grundpfandrecht, das an eine bestimmte Forderung gebunden ist (akzessorisch). Heute weitgehend durch Grundschuld ersetzt.', 'Finanzierung', '§ 1113 BGB', 'https://www.gesetze-im-internet.de/bgb/__1113.html'),
('Indexmiete', 'Mietvertrag, bei dem die Miete an die Entwicklung des Verbraucherpreisindex gekoppelt ist. Mieterhöhungen erfolgen automatisch bei Indexänderung.', 'Verwaltung', '§ 557b BGB', 'https://www.gesetze-im-internet.de/bgb/__557b.html'),
('Instandhaltungsrücklage', 'Ansammlung einer angemessenen Geldsumme durch die Wohnungseigentümergemeinschaft zur Sicherung der langfristigen Erhaltung des Gebäudes (jetzt: Erhaltungsrücklage).', 'Verwaltung', '§ 19 Abs. 2 Nr. 4 WEG', 'https://www.gesetze-im-internet.de/woeigg/__19.html'),
('Insolvenz', 'Zahlungsunfähigkeit oder Überschuldung eines Schuldners. Eröffnung des Insolvenzverfahrens zur gleichmäßigen Befriedigung der Gläubiger.', 'Recht', '§ 1 InsO', 'https://www.gesetze-im-internet.de/inso/__1.html'),
('Jahresabrechnung', 'Aufstellung aller Einnahmen und Ausgaben einer WEG für ein Wirtschaftsjahr. Muss vom Verwalter erstellt und von der Eigentümerversammlung genehmigt werden.', 'Verwaltung', '§ 28 WEG', 'https://www.gesetze-im-internet.de/woeigg/__28.html'),
('Juristische Person', 'Rechtsfähige Organisation (z.B. GmbH, AG, Verein), die wie eine natürliche Person Rechte und Pflichten haben kann. Wichtig bei gewerblichen Immobiliengeschäften.', 'Recht', '§ 21 BGB', 'https://www.gesetze-im-internet.de/bgb/__21.html'),
('Kataster', 'Amtliches Verzeichnis aller Grundstücke (Liegenschaftskataster) mit Angaben zu Lage, Größe, Nutzungsart und Eigentümer.', 'Bau', NULL, NULL),
('Kaufpreisaufteilung', 'Aufteilung des Gesamtkaufpreises auf Grund und Boden sowie Gebäude. Wichtig für steuerliche Abschreibung (AfA), da nur Gebäude abschreibbar ist.', 'Finanzierung', NULL, NULL),
('Kreditwürdigkeit (Bonität)', 'Fähigkeit und Bereitschaft eines Kreditnehmers, einen Kredit zurückzuzahlen. Wird von Banken anhand von Einkommen, Vermögen und Schufa-Score geprüft.', 'Finanzierung', NULL, NULL),
('Laufzeit', 'Zeitraum, für den ein Darlehen vereinbart wird. Bei Immobilienkrediten oft 20-30 Jahre Gesamtlaufzeit mit kürzeren Zinsbindungsfristen.', 'Finanzierung', NULL, NULL),
('Liegenschaftszins', 'Zinssatz, mit dem der Verkehrswert von Grundstücken im Durchschnitt marktüblich verzinst wird. Wichtige Größe im Ertragswertverfahren.', 'Finanzierung', '§ 14 ImmoWertV', 'https://www.gesetze-im-internet.de/immowertv_2021/__14.html'),
('Makleralleinauftrag', 'Vertrag, bei dem sich der Auftraggeber verpflichtet, für die Vertragslaufzeit keine anderen Makler einzuschalten. Beim qualifizierten Alleinauftrag darf er auch nicht mehr privat verkaufen.', 'Makler', NULL, NULL),
('Mietkaution', 'Sicherheitsleistung des Mieters, maximal drei Nettokaltmieten. Muss vom Vermieter verzinslich angelegt werden.', 'Verwaltung', '§ 551 BGB', 'https://www.gesetze-im-internet.de/bgb/__551.html'),
('Mietminderung', 'Recht des Mieters, die Miete zu kürzen, wenn die Mietsache einen Mangel aufweist, der die Tauglichkeit zum vertragsgemäßen Gebrauch erheblich mindert.', 'Verwaltung', '§ 536 BGB', 'https://www.gesetze-im-internet.de/bgb/__536.html'),
('Mietpreisbremse', 'Regelung, die die Miethöhe bei Wiedervermietung in angespannten Wohnungsmärkten auf maximal 10% über der ortsüblichen Vergleichsmiete begrenzt.', 'Recht', '§ 556d BGB', 'https://www.gesetze-im-internet.de/bgb/__556d.html'),
('Mietspiegel', 'Übersicht über die ortsübliche Vergleichsmiete. Dient als Grundlage für Mieterhöhungen und zur Beurteilung der Angemessenheit von Mieten.', 'Verwaltung', '§ 558c BGB', 'https://www.gesetze-im-internet.de/bgb/__558c.html'),
('Modernisierung', 'Baumaßnahmen, die den Gebrauchswert der Mietsache nachhaltig erhöhen, die allgemeinen Wohnverhältnisse verbessern oder Energie/Wasser sparen. Berechtigt zu Mieterhöhung.', 'Bau', '§ 555b BGB', 'https://www.gesetze-im-internet.de/bgb/__555b.html'),
('Nachrangfinanzierung', 'Kredit, der im Grundbuch hinter einer erstrangigen Finanzierung eingetragen wird. Höheres Risiko für Bank, daher höhere Zinsen.', 'Finanzierung', NULL, NULL),
('Nebenkosten', 'Beim Immobilienkauf: Grunderwerbsteuer, Notar- und Grundbuchkosten, Maklercourtage (ca. 10-15% des Kaufpreises). Bei Vermietung: siehe Betriebskosten.', 'Finanzierung', NULL, NULL),
('Nießbrauch', 'Das umfassende Nutzungsrecht an einer fremden Sache (z.B. Immobilie). Der Nießbraucher darf die Früchte ziehen (z.B. Mieteinnahmen), muss aber meist auch die Lasten tragen.', 'Recht', '§ 1030 BGB', 'https://www.gesetze-im-internet.de/bgb/__1030.html'),
('Notaranderkonto', 'Treuhandkonto eines Notars zur Abwicklung von Zahlungen (z.B. Kaufpreis). Wird heute nur noch bei berechtigtem Sicherungsinteresse genutzt.', 'Recht', '§ 54 BeurkG', 'https://www.gesetze-im-internet.de/beurkg/__54.html'),
('Nutzfläche', 'Fläche eines Gebäudes, die der Nutzung dient (ohne Verkehrsflächen und technische Funktionsflächen). Berechnung nach DIN 277.', 'Bau', 'DIN 277', NULL),
('Objektbesichtigung', 'Vor-Ort-Termin zur Besichtigung einer Immobilie durch Interessenten. Makler müssen auf wesentliche Mängel hinweisen.', 'Makler', NULL, NULL),
('Ortsübliche Vergleichsmiete', 'Durchschnittliche Miete für vergleichbare Wohnungen in der Gemeinde. Maßstab für Mieterhöhungen und Mietpreisbremse.', 'Verwaltung', '§ 558 BGB', 'https://www.gesetze-im-internet.de/bgb/__558.html'),
('Rangstelle', 'Position einer Grundschuld oder Hypothek im Grundbuch. Je niedriger die Rangstelle, desto besser die Absicherung bei Zwangsversteigerung.', 'Finanzierung', NULL, NULL),
('Reallast', 'Dingliches Recht, aus einem Grundstück wiederkehrende Leistungen zu fordern (z.B. Rentenzahlungen, Versorgungsleistungen).', 'Recht', '§ 1105 BGB', 'https://www.gesetze-im-internet.de/bgb/__1105.html'),
('Restschuld', 'Noch nicht getilgter Betrag eines Darlehens. Am Ende der Zinsbindung oft noch erhebliche Restschuld vorhanden (Anschlussfinanzierung nötig).', 'Finanzierung', NULL, NULL),
('Sachverständiger', 'Fachkundige Person zur Bewertung von Immobilien oder Feststellung von Mängeln. Öffentlich bestellte Sachverständige haben besondere Qualifikation.', 'Allgemein', '§ 36 GewO', 'https://www.gesetze-im-internet.de/gewo/__36.html'),
('Sachwertverfahren', 'Wertermittlungsverfahren für selbstgenutzte Immobilien. Wert = Bodenwert + Gebäudesachwert (Herstellungskosten minus Alterswertminderung).', 'Finanzierung', '§§ 21-23 ImmoWertV', 'https://www.gesetze-im-internet.de/immowertv_2021/__21.html'),
('Schönheitsreparaturen', 'Renovierungsarbeiten wie Tapezieren, Streichen, Lackieren. Können im Mietvertrag auf Mieter übertragen werden, aber nur bei wirksamer Klausel.', 'Verwaltung', '§ 535 BGB', 'https://www.gesetze-im-internet.de/bgb/__535.html'),
('Sondereigentum', 'Das Alleineigentum an einer bestimmten Wohnung oder an nicht zu Wohnzwecken dienenden Räumen in einem Gebäude.', 'Verwaltung', '§ 5 WEG', 'https://www.gesetze-im-internet.de/woeigg/__5.html'),
('Sondernutzungsrecht', 'Recht eines Wohnungseigentümers, einen Teil des Gemeinschaftseigentums allein zu nutzen (z.B. Garten, Stellplatz, Dachboden).', 'Verwaltung', '§ 13 WEG', 'https://www.gesetze-im-internet.de/woeigg/__13.html'),
('Staffelmiete', 'Mietvertrag mit von vornherein festgelegten Mieterhöhungen zu bestimmten Zeitpunkten. Andere Mieterhöhungen sind ausgeschlossen.', 'Verwaltung', '§ 557a BGB', 'https://www.gesetze-im-internet.de/bgb/__557a.html'),
('Teilungserklärung', 'Erklärung des Grundstückseigentümers gegenüber dem Grundbuchamt, dass das Eigentum am Grundstück in Miteigentumsanteile aufgeteilt wird, die mit Sondereigentum verbunden sind.', 'Recht', '§ 8 WEG', 'https://www.gesetze-im-internet.de/woeigg/__8.html'),
('Tilgung', 'Rückzahlung eines Darlehens. Bei Annuitätendarlehen steigt die Tilgungsrate im Zeitverlauf, da der Zinsanteil sinkt.', 'Finanzierung', NULL, NULL),
('Treuhandvertrag', 'Vertrag, bei dem eine Person (Treuhänder) Vermögen im eigenen Namen, aber für fremde Rechnung verwaltet. Oft bei Bauträgerverträgen.', 'Recht', NULL, NULL),
('Umlegung', 'Neuordnung von Grundstücken zur Schaffung zweckmäßiger Baugrundstücke. Häufig im Rahmen von Bebauungsplänen.', 'Bau', '§§ 45 ff. BauGB', 'https://www.gesetze-im-internet.de/bbaugb/__45.html'),
('Unbedenklichkeitsbescheinigung', 'Bescheinigung des Finanzamts, dass die Grunderwerbsteuer gezahlt wurde (oder nicht anfällt). Voraussetzung für die Eigentumsumschreibung im Grundbuch.', 'Recht', '§ 22 GrEStG', 'https://www.gesetze-im-internet.de/grestg_1983/__22.html'),
('Vergleichswertverfahren', 'Wertermittlungsverfahren, bei dem der Wert durch Vergleich mit tatsächlich erzielten Kaufpreisen ähnlicher Objekte ermittelt wird.', 'Finanzierung', '§§ 15-16 ImmoWertV', 'https://www.gesetze-im-internet.de/immowertv_2021/__15.html'),
('Verkehrswert (Marktwert)', 'Der Preis, der zum Zeitpunkt der Ermittlung im gewöhnlichen Geschäftsverkehr nach den rechtlichen Gegebenheiten und tatsächlichen Eigenschaften zu erzielen wäre.', 'Finanzierung', '§ 194 BauGB', 'https://www.gesetze-im-internet.de/bbaugb/__194.html'),
('Vorkaufsrecht', 'Recht, beim Verkauf eines Grundstücks an einen Dritten zu den gleichen Bedingungen einzutreten. Kann gesetzlich (Gemeinde) oder vertraglich bestehen.', 'Recht', '§§ 24-28 BauGB, § 463 BGB', 'https://www.gesetze-im-internet.de/bbaugb/__24.html'),
('Vorfälligkeitsentschädigung', 'Entschädigung an die Bank bei vorzeitiger Rückzahlung eines Darlehens während der Zinsbindung. Kompensiert entgangene Zinsen.', 'Finanzierung', '§ 490 Abs. 2 BGB', 'https://www.gesetze-im-internet.de/bgb/__490.html'),
('Wegerecht', 'Dienstbarkeit, die dem Berechtigten das Recht gibt, über ein fremdes Grundstück zu gehen oder zu fahren. Wird im Grundbuch eingetragen.', 'Recht', '§ 1018 BGB', 'https://www.gesetze-im-internet.de/bgb/__1018.html'),
('Wertgutachten', 'Schriftliche Stellungnahme eines Sachverständigen über den Wert einer Immobilie. Grundlage für Kreditentscheidungen, Erbauseinandersetzungen, Scheidungen.', 'Allgemein', NULL, NULL),
('Widerrufsrecht', 'Recht des Verbrauchers, sich innerhalb einer bestimmten Frist (meist 14 Tage) ohne Angabe von Gründen von einem Vertrag zu lösen (z.B. Maklervertrag, Darlehensvertrag).', 'Recht', '§ 355 BGB', 'https://www.gesetze-im-internet.de/bgb/__355.html'),
('Wohnflächenberechnung', 'Ermittlung der anrechenbaren Grundfläche einer Wohnung. Maßgeblich ist meist die Wohnflächenverordnung (WoFlV).', 'Bau', 'WoFlV', 'https://www.gesetze-im-internet.de/woflv/'),
('Wohnrecht', 'Persönliches Recht, eine Wohnung oder ein Haus lebenslang oder zeitlich begrenzt zu bewohnen. Kann als Dienstbarkeit im Grundbuch eingetragen werden.', 'Recht', '§ 1093 BGB', 'https://www.gesetze-im-internet.de/bgb/__1093.html'),
('Zwangsversteigerung', 'Staatliches Verfahren zur Durchsetzung privatrechtlicher Ansprüche (z.B. Geldforderungen) mit staatlicher Gewalt (Gerichtsvollzieher, Zwangsversteigerung).', 'Recht', '§ 866 ZPO', 'https://www.gesetze-im-internet.de/zpo/__866.html'),
('Zwangsverwaltung', 'Zwangsvollstreckung in eine Immobilie durch Einsetzung eines Zwangsverwalters, der die Erträge (Mieten) einzieht und an Gläubiger verteilt.', 'Recht', '§ 146 ZVG', 'https://www.gesetze-im-internet.de/zvg/__146.html'),
('Zweckentfremdung', 'Nutzung von Wohnraum zu anderen als Wohnzwecken (z.B. Ferienwohnung, Büro). In vielen Städten genehmigungspflichtig.', 'Recht', NULL, NULL);